#include <bits/stdc++.h>
using namespace std;
struct Node{
    int id,nl;
}t;
int main(){
    int n;
    queue<Node> a;
    cin>>n;
    for(int i=1;i<=(1<<n);i++){
        cin>>t.nl;
        t.id=i;
        a.push(t);
    }
    while(a.size()>2){
        int len=a.size();
        for(int i=1;i<=len/2;i++){
            Node x=a.front(),y;
            a.pop();
            y=a.front();
            a.pop();
            a.push(x.nl<y.nl? y:x);
        }
    }
    Node x=a.front(),y;
    a.pop(),y=a.front(),a.pop();
    cout<<(x.nl<y.nl? x.id:y.id);
    return 0;
}
